                                            <SelectTrigger className="h-9 text-sm"><SelectValue placeholder="Chọn" /></SelectTrigger>
                                            <SelectContent>
                                                {MARITAL_STATUS_OPTIONS.map(opt => <SelectItem key={opt.value} value={opt.value} className="text-xs">{opt.label}</SelectItem>)}
                                            </SelectContent>
                                        </Select>
