                                                <SelectItem value="PROBATION" className="text-xs">Thử việc</SelectItem>
                                                <SelectItem value="OFFICIAL" className="text-xs">Chính thức</SelectItem>
                                                <SelectItem value="SEASONAL" className="text-xs">Thời vụ</SelectItem>
                                                <SelectItem value="MATERNITY_LEAVE" className="text-xs">Thai sản</SelectItem>
                                                <SelectItem value="RESIGNED" className="text-xs">Đã nghỉ việc</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                </div>
