                                    <div className="space-y-1.5">
                                        <Label className="text-[11px] font-semibold text-muted-foreground uppercase tracking-wider">Email cá nhân</Label>
                                        <Input type="email" {...register("personalEmail")} className="h-9 text-sm" />
